from typing import List, Optional
import numpy as np


def fixed_size_chunk(text: str, chunk_size: int = 200, overlap: int = 50) -> List[str]:
    """Split text into fixed-size character chunks with overlap."""
    chunks: List[str] = []
    start = 0
    while start < len(text):
        end = start + chunk_size
        chunks.append(text[start:end])
        start += chunk_size - overlap
    return chunks


def recursive_chunk(
    text: str,
    chunk_size: int = 200,
    separators: Optional[List[str]] = None
) -> List[str]:
    """Recursively split text using a hierarchy of separators."""
    if separators is None:
        separators = ['\n\n', '\n', '. ', ' ']

    if len(text) <= chunk_size:
        return [text] if text.strip() else []

    chunks: List[str] = []
    for i, sep in enumerate(separators):
        if sep in text:
            parts = text.split(sep)
            current = ""
            for part in parts:
                candidate = current + sep + part if current else part
                if len(candidate) <= chunk_size:
                    current = candidate
                else:
                    if current:
                        chunks.append(current)
                    if len(part) > chunk_size and i + 1 < len(separators):
                        chunks.extend(recursive_chunk(part, chunk_size, separators[i+1:]))
                    else:
                        current = part
            if current:
                chunks.append(current)
            return chunks

    # Fallback: hard split
    return fixed_size_chunk(text, chunk_size, overlap=0)


def semantic_chunk(
    sentences: List[str],
    similarity_matrix: np.ndarray,
    threshold: float = 0.5
) -> List[str]:
    """Group consecutive sentences by semantic similarity."""
    if not sentences:
        return []
    if len(sentences) == 1:
        return [sentences[0]]

    chunks: List[str] = []
    current_group: List[str] = [sentences[0]]

    for i in range(len(sentences) - 1):
        sim = similarity_matrix[i][i + 1]
        if sim >= threshold:
            current_group.append(sentences[i + 1])
        else:
            chunks.append(' '.join(current_group))
            current_group = [sentences[i + 1]]

    if current_group:
        chunks.append(' '.join(current_group))

    return chunks

