from typing import List, Dict, Optional


class PromptTemplate:
    def __init__(
        self,
        name: str,
        version: str,
        template: str,
        variables: List[str],
        few_shot_examples: Optional[List[Dict[str, str]]] = None
    ):
        self.name = name
        self.version = version
        self.template = template
        self.variables = variables
        self.few_shot_examples = few_shot_examples or []

    def render(self, **kwargs: str) -> str:
        """Render the template with variable substitution."""
        missing = set(self.variables) - set(kwargs.keys())
        # Don't count few_shot_block as missing if it's handled separately
        missing.discard('few_shot_block')
        if missing:
            raise ValueError(f"Missing variables: {missing}")

        result = self.template

        # Handle few-shot block
        if '{{few_shot_block}}' in result and self.few_shot_examples:
            few_shot_text = '\n\n'.join(
                f"Input: {ex['input']}\nOutput: {ex['output']}"
                for ex in self.few_shot_examples
            )
            result = result.replace('{{few_shot_block}}', few_shot_text)
        elif '{{few_shot_block}}' in result:
            result = result.replace('{{few_shot_block}}', '')

        # Substitute variables
        for var, value in kwargs.items():
            result = result.replace(f"{{{{{var}}}}}", value)

        return result

    def token_estimate(self) -> int:
        """Estimate token count as word count."""
        return len(self.template.split())


class PromptRegistry:
    def __init__(self) -> None:
        self._templates: Dict[str, Dict[str, PromptTemplate]] = {}

    def register(self, template: PromptTemplate) -> None:
        if template.name not in self._templates:
            self._templates[template.name] = {}
        self._templates[template.name][template.version] = template

    def get(self, name: str, version: Optional[str] = None) -> PromptTemplate:
        if name not in self._templates:
            raise KeyError(f"Template '{name}' not found")
        versions = self._templates[name]
        if version:
            if version not in versions:
                raise KeyError(f"Version '{version}' not found for '{name}'")
            return versions[version]
        latest = sorted(versions.keys())[-1]
        return versions[latest]

    def list_versions(self, name: str) -> List[str]:
        if name not in self._templates:
            return []
        return sorted(self._templates[name].keys())

    def rollback(self, name: str) -> PromptTemplate:
        versions = self.list_versions(name)
        if len(versions) < 2:
            raise ValueError(f"Cannot rollback '{name}': fewer than 2 versions")
        previous_version = versions[-2]
        return self._templates[name][previous_version]

import re
from typing import List, Dict


def extract_invoice(text: str) -> dict:
    """Extract structured fields from invoice text."""
    # Extract invoice number
    inv_patterns = [
        r'(?:Invoice|INV)[\s#:.-]*([A-Z0-9][-A-Z0-9]*)',
        r'(?:Invoice|INV)[\s#:.-]*(\d+)',
    ]
    invoice_number = 'UNKNOWN'
    for pattern in inv_patterns:
        match = re.search(pattern, text, re.IGNORECASE)
        if match:
            invoice_number = match.group(1)
            break

    # Extract date
    date_patterns = [
        r'(\d{1,2}[/-]\d{1,2}[/-]\d{4})',
        r'(\d{4}[/-]\d{1,2}[/-]\d{1,2})',
    ]
    date = 'UNKNOWN'
    for pattern in date_patterns:
        match = re.search(pattern, text)
        if match:
            date = match.group(1)
            break

    # Extract total
    total_patterns = [
        r'(?:Total|Amount\s*Due|Balance)[\s:]*\$?([\d,]+\.?\d*)',
        r'(?:Total|Amount\s*Due|Balance)[\s:]*€([\d,]+\.?\d*)',
    ]
    total = 0.0
    for pattern in total_patterns:
        match = re.search(pattern, text, re.IGNORECASE)
        if match:
            total = float(match.group(1).replace(',', ''))
            break

    # Extract line items
    line_items: List[Dict] = []
    # Match lines with dollar/euro amount at the end
    item_pattern = r'^(.+?)\s+\$([\d,]+\.?\d*)\s*$'
    for line in text.split('\n'):
        match = re.match(item_pattern, line.strip())
        if match:
            desc = match.group(1).strip()
            amount = float(match.group(2).replace(',', ''))
            # Skip lines that look like totals/subtotals
            if not re.match(r'(?:Total|Subtotal|Tax|Amount Due|Balance)', desc, re.IGNORECASE):
                line_items.append({'description': desc, 'amount': amount})

    # Detect currency
    currency = 'UNKNOWN'
    if '$' in text:
        currency = 'USD'
    elif '€' in text:
        currency = 'EUR'

    return {
        'invoice_number': invoice_number,
        'date': date,
        'total': total,
        'line_items': line_items,
        'currency': currency,
    }


def validate_invoice(invoice: dict) -> dict:
    """Validate extracted invoice data and compute confidence."""
    issues: List[str] = []
    confidence = 0.0

    if invoice.get('invoice_number', 'UNKNOWN') != 'UNKNOWN':
        confidence += 0.25
    else:
        issues.append('Missing invoice number')

    if invoice.get('date', 'UNKNOWN') != 'UNKNOWN':
        confidence += 0.25
    else:
        issues.append('Missing date')

    if invoice.get('total', 0.0) > 0:
        confidence += 0.25
    else:
        issues.append('Missing or zero total')

    if invoice.get('line_items', []):
        confidence += 0.25
    else:
        issues.append('No line items found')

    is_valid = (
        invoice.get('invoice_number', 'UNKNOWN') != 'UNKNOWN'
        and invoice.get('date', 'UNKNOWN') != 'UNKNOWN'
        and invoice.get('total', 0.0) > 0
    )

    return {
        'is_valid': is_valid,
        'confidence': confidence,
        'issues': issues,
    }
